```cpp
#include <iostream>
#include <unistd.h>
#include <sys/types.h>
#include <sys/wait.h>

int main() {
    pid_t pid;
    int fd[2];
    pipe(fd); // Создаем трубу

    if ((pid = fork()) == -1) {
        std::cerr << "Ошибка при создании дочернего процесса" << std::endl;
        return 1;
    } else if (pid == 0) { // Дочерний процесс
        close(fd[1]); // Закрываем дескриптор для записи
        dup2(fd[0], 0); // Соединяем стандартный ввод с дескриптором для чтения
        close(fd[0]); // Закрываем дескриптор для чтения (не нужен)

        execlp("ls", "ls", NULL); // Запускаем команду ls
    } else { // Родительский процесс
        close(fd[0]); // Закрываем дескриптор для чтения
        dup2(fd[1], 1); // Соединяем стандартный вывод с дескриптором для записи
        close(fd[1]); // Закрываем дескриптор для записи (не нужен)

        std::cout << "Родительский процесс" << std::endl;
        wait(NULL); // Ждем завершения дочернего процесса
    }

    return 0;
}
```

Этот код создает новый процесс, соединяет его стандартный ввод и вывод с одним файловым дескриптором (труба), и запускает команду `ls`.

